const _TWO_PI = 2 * Math.PI;
/////////////////////////////////////////////////////////////////////////////////////////////////////////////
class Point {
    x;
    y;
    constructor(x, y) {
        this.x = x;
        this.y = y;
    }
    toString() {
        return `(${this.x}, ${this.y})`;
    }
}
